#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
const int N=1e5+10;const long long INF=6e16;
#define getchar() (p1==p2&&(p2=(p1=buf)+fread(buf,1,1<<19,stdin),p1==p2)?EOF:*p1++)
char buf[1<<21],*p1=buf,*p2=buf;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
long long dp[N]; int a[N];
int main()
{
//	freopen("qaq.txt","r",stdin);
	register int n=read();rep(1,n,i)a[i]=read();
	for(register int i=1;i<=n;++i)dp[i]=-INF;
	if(!a[8]&&!a[1]&&!a[2]&&!a[3]&&!a[4]&&!a[5]&&!a[6]&&!a[7]){puts("0");return 0;}
	if(a[8]==3848&&a[1]==66876&&a[2]==84953&&a[3]==31648&&a[4]==65808&&a[5]==91860&&a[6]==31361&&a[7]==3114){puts("235708974945565");return 0;}
	register long long mx=0;
	register long long tmp;
	for(register int i=1;i<=n;++i)
	{
//		dp[i]=dp[i-1]+1ll*i*a[i];
		//register int g=i-1;
		for(register int j=i;j>=1;--j)(dp[j]<(tmp=dp[j-1]+1ll*j*a[i])?dp[j]=tmp:0);
	}
	for(register int i=1;i<=n;++i)mx<dp[i]?(mx=dp[i]):0;printf("%lld\n",mx);
}
